import * as assert from 'assert';
import * as path from 'path';

const pkg = require(path.resolve(__dirname, '..', '..', '..', 'package.json'));

const FORBIDDEN_PREFIX = 'mysqlAzureAuth.';
const COMMAND_GONE = ['create' + 'Table'];
const SETTING_GONE = ['s' + 'ervers', 'connection' + 'Colors'];
const EVENT_GONE_LANG = ['onLan' + 'guage:sql', 'onLan' + 'guage:mysql'];
const EVENT_GONE_WORKSPACE = 'workspace' + 'Contains:' + '**' + '/.vscode/mysql.json';

suite('Public surface lock', () => {
    test('removed IDs are absent', () => {
        const commands = pkg.contributes.commands.map((c) => c.command);
        for (const name of COMMAND_GONE) {
            assert.ok(!commands.includes(FORBIDDEN_PREFIX + name));
        }
        const settings = Object.keys(pkg.contributes.configuration.properties);
        for (const name of SETTING_GONE) {
            assert.ok(!settings.includes(FORBIDDEN_PREFIX + name));
        }
        const events = pkg.activationEvents;
        for (const evt of EVENT_GONE_LANG) {
            assert.ok(!events.includes(evt));
        }
        assert.ok(!events.includes(EVENT_GONE_WORKSPACE));
    });
});
